const sd = $getWorkflowStaticData('global');
sd.crosssell = sd.crosssell || [];
const setup = $('⚙️ Setup').first().json;
const orders = (($('📥 Käufe von vor X Tagen').first().json.orders) || []).filter(o => !o.cancelled_at && o.email);
const katalog = (($json.products) || []).slice(0, 25)
  .map(p => '- ' + p.title + ' | Typ: ' + (p.product_type || '-') + ' | Preis: ' + (((p.variants || [])[0] || {}).price || '?') + ' | Link: ' + setup.SHOP_URL + '/products/' + p.handle)
  .join('\n');
const raus = [];

for (const o of orders) {
  if (sd.crosssell.includes(o.id)) continue;
  sd.crosssell.push(o.id);
  const gekauft = (o.line_items || []).map(li => li.title).join(', ');
  const vorname = (o.customer && o.customer.first_name) || '';

  const prompt = 'Du bist Empfehlungs-Experte fuer den Onlineshop "' + setup.SHOP_NAME + '".\n' +
    'Der Kunde hat vor ' + setup.KAUF_VOR_TAGEN + ' Tagen gekauft: ' + gekauft + '\n' +
    'Vorname: ' + (vorname || 'unbekannt (neutral anreden)') + '\n\n' +
    'Produktkatalog:\n' + katalog + '\n\n' +
    'Aufgabe:\n' +
    '1. Waehle aus dem Katalog 1-2 Produkte, die WIRKLICH sinnvoll zum Gekauften passen (ergaenzen, nicht ersetzen!). Wenn nichts wirklich passt, nimm die 1-2 beliebtesten Allrounder.\n' +
    '2. Schreibe eine persoenliche Empfehlungs-Mail auf Deutsch (Du-Form), max 120 Woerter: Einstieg = kurze Frage, wie er mit dem gekauften Produkt zufrieden ist. Dann die Empfehlung als ehrlichen Tipp formulieren ("Kunden, die X haben, lieben Y, weil...") mit Produktlink(s) als Button/Link. KEIN Rabatt noetig - die Empfehlung selbst ist der Wert.\n' +
    'Mobiltaugliches HTML mit Inline-CSS. Antworte NUR mit validem JSON, ohne Markdown-Codeblock: {"betreff": "...", "html": "..."}';

  raus.push({ json: { order_id: o.id, email: o.email, vorname, prompt } });
}

if (sd.crosssell.length > 2000) sd.crosssell = sd.crosssell.slice(-2000);
return raus;

const blocks = $json.content || [];
const text = (blocks.find(b => b.type === 'text') || {}).text || '';
let daten;
try {
  daten = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch (e) {
  daten = { betreff: 'Das koennte dir auch gefallen ✨', html: text };
}
const orig = $('🧠 Passende Produkte finden').item.json;
const setup = $('⚙️ Setup').first().json;
const empfaenger = setup.TEST_MODE === 'ja' ? setup.OWNER_EMAIL : orig.email;
return { json: {
  empfaenger,
  betreff: (setup.TEST_MODE === 'ja' ? '[TEST] ' : '') + daten.betreff,
  email_html: daten.html
}};
